/**
 * @summary Export measurements as CSV
 */
export const getExportMeasurementsCsvUrl = (
  params?: ExportMeasurementsCsvParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/reports/measurements/csv?${stringifiedParams}`
    : `/api/reports/measurements/csv`;
};

export const exportMeasurementsCsv = async (
  params?: ExportMeasurementsCsvParams,
  options?: RequestInit,
): Promise<string> => {
  return customFetch<string>(getExportMeasurementsCsvUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getExportMeasurementsCsvQueryKey = (
  params?: ExportMeasurementsCsvParams,
) => {
  return [
    `/api/reports/measurements/csv`,
    ...(params ? [params] : []),
  ] as const;
};

